#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T, N, P;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &P);
        int S[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &S[i]);
        }
        qsort(S, N, sizeof(int), compare);
        int ans[N];
        for (int i = 0; i < N; i++) {
            int count = 0;
            for (int j = 0; j < N; j++) {
                int temp = P;
                for (int k = j; k <= i; k++) {
                    temp -= S[k];
                    if (temp <= 0) {
                        break;
                    }
                }
                if (temp <= 0) {
                    count++;
                }
            }
            ans[i] = count;
        }
        for (int i = 0; i < N; i++) {
            printf("%d ", ans[i]);
        }
        printf("\n");
    }
    return 0;
}

